class Solution:
    def findUnsortedSubarray(self, nums):
        s = sorted(nums)
        n = len(nums)
        first = -1
        last = -1
        for i in range(n):
            if nums[i] != s[i]:
                if first == -1:
                    first = i
                last = i
        if first == -1:
            return 0
        return last - first + 1

