var findUnsortedSubarray = function(nums) {
    const n = nums.length;
    let maxSeen = -Infinity, right = -1;
    for (let i = 0; i < n; i++) {
        if (nums[i] < maxSeen) right = i;
        else maxSeen = nums[i];
    }
    let minSeen = Infinity, left = -1;
    for (let i = n - 1; i >= 0; i--) {
        if (nums[i] > minSeen) left = i;
        else minSeen = nums[i];
    }
    if (right === -1) return 0;
    return right - left + 1;
};
